// null = never chosen (will trigger first-load picker)
function readUserCookie() {
  const m = document.cookie.match(/(?:^|;\s*)movieclub_user=([^;]*)/);
  if (!m) return null;
  try { return JSON.parse(decodeURIComponent(m[1])); } catch { return null; }
}
function writeUserCookie(userObj) {
  const exp = new Date(Date.now() + 365*24*60*60*1000).toUTCString();
  document.cookie = `movieclub_user=${encodeURIComponent(JSON.stringify(userObj))};expires=${exp};path=/`;
}
const UserContext = React.createContext(null);

async function fetchTrailerUrl(tmdbId) {
  if (!tmdbId) return null;
  try {
    const res = await fetch(`https://api.themoviedb.org/3/movie/${tmdbId}/videos?api_key=${TMDB_KEY}`);
    const data = await res.json();
    const trailer = (data.results || []).find(v => v.type === 'Trailer' && v.site === 'YouTube');
    return trailer ? `https://www.youtube.com/embed/${trailer.key}?rel=0` : null;
  } catch(e) { return null; }
}

