function getTriviaOfTheWeek() {
  const weekNum = Math.floor(Date.now() / (7 * 24 * 60 * 60 * 1000));
  return TRIVIA_BANK[weekNum % TRIVIA_BANK.length];
}

// ─── HELPERS ─────────────────────────────────────────────────────────────────
const ACCENT_COLORS = ['#d63a2f','#2563b8','#2a7a3b','#e8621a','#7c3aed','#b8860b'];

function avg(arr) {
  const nums = arr.filter(n => n > 0);
  if (!nums.length) return null;
  return (nums.reduce((a,b) => a+b, 0) / nums.length).toFixed(1);
}

// ─── MONTH SORT HELPER ───────────────────────────────────────────────────────
const MONTH_NAMES = ['January','February','March','April','May','June','July','August','September','October','November','December'];
function parseMonthYear(str) {
  if (!str) return 0;
  const clean = str.replace(/[^\w\s]/g, ' ').replace(/\s+/g, ' ').trim();
  const yearMatch = clean.match(/\d{4}/);
  if (!yearMatch) return 0;
  const year = parseInt(yearMatch[0]);
  for (let i = 0; i < MONTH_NAMES.length; i++) {
    if (clean.indexOf(MONTH_NAMES[i]) >= 0) return year * 12 + i;
  }
  return year * 12;
}

// ─── URL / ROUTING HELPERS ───────────────────────────────────────────────────
function slugify(str) {
  return (str || '').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '').substring(0, 60);
}
